import { Bot, Context, session, SessionFlavor } from 'grammy';

// 1. Session shaklini interface bilan aniqlaymiz.
//    Bu yerda form wizard bosqichi va vaqtinchalik ma'lumot saqlanadi.
interface SessionData {
  step: 'idle' | 'ask_name' | 'ask_phone'; // suhbat bosqichi
  draftName?: string;                       // wizard davomida yigilgan qiymat
  lastActionAt?: number;                    // oxirgi harakat vaqti (ms)
}

// 2. Context flavor: ctx.session endi SessionData tipida bo'ladi.
type MyContext = Context & SessionFlavor<SessionData>;

const bot = new Bot<MyContext>(process.env.BOT_TOKEN!);

// 3. initial() har yangi chat uchun boshlangich qiymat qaytaradi.
bot.use(session({
  initial: (): SessionData => ({ step: 'idle' }),
}));

bot.command('order', (ctx) => {
  ctx.session.step = 'ask_name'; // tiplangan: notogri qiymat compile xatosi
  return ctx.reply('Ismingizni yozing:');
});

bot.on('message:text', (ctx) => {
  if (ctx.session.step === 'ask_name') {
    ctx.session.draftName = ctx.message.text;
    ctx.session.step = 'ask_phone';
    return ctx.reply('Telefon raqamingizni yozing:');
  }
});

