import { NextFunction } from 'grammy';
import { Prisma } from '@prisma/client';
import { prisma } from './db';
import type { MyContext } from './context';

// Middleware: har update faqat bir marta ishlanadi.
export async function idempotency(ctx: MyContext, next: NextFunction) {
  const updateId = ctx.update.update_id;
  try {
    // Unique @id tufayli takror insert xato beradi.
    await prisma.processedUpdate.create({ data: { updateId } });
  } catch (err) {
    if (
      err instanceof Prisma.PrismaClientKnownRequestError &&
      err.code === 'P2002' // unique constraint buzildi
    ) {
      console.warn(`Takror update ${updateId} - otkazib yuborildi`);
      return; // handlerga bormaydi, Telegram retry zararsiz
    }
    throw err;
  }
  await next();
}

