import { bot } from './bot';
import { db } from './db';

// 1. Invoice yuborish - order oldindan 'pending' holatda DB'da yaratiladi.
bot.command('buy', async (ctx) => {
  const order = await db.order.create({
    data: { userId: ctx.from!.id, status: 'pending', amount: 49900 },
  });
  await ctx.replyWithInvoice(
    'Pro obuna', '1 oylik Pro dostup',
    order.id, // payload: successful_payment'da order'ni topamiz
    process.env.PROVIDER_TOKEN!, 'UZS',
    [{ label: 'Pro (1 oy)', amount: 49900 }],
  );
});

// 2. Pre-checkout: ~10s ichida javob berish shart, aks holda to'lov bekor bo'ladi.
bot.on('pre_checkout_query', async (ctx) => {
  const order = await db.order.findUnique({
    where: { id: ctx.preCheckoutQuery.invoice_payload },
  });
  const ok = !!order && order.status === 'pending' &&
    order.amount === ctx.preCheckoutQuery.total_amount;
  // ok=false bo'lsa Telegram to'lovni to'xtatadi.
  await ctx.answerPreCheckoutQuery(ok, ok ? undefined : 'Order eskirgan yoki narx notogri');
});

// 3. Muvaffaqiyatli to'lov: order'ni faqat 'pending' bo'lsa yangilaymiz (idempotent).
bot.on('message:successful_payment', async (ctx) => {
  const p = ctx.message.successful_payment;
  const res = await db.order.updateMany({
    where: { id: p.invoice_payload, status: 'pending' },
    data: {
      status: 'paid',
      providerChargeId: p.provider_payment_charge_id, // faqat charge_id, karta emas
      paidAt: new Date(),
    },
  });
  // res.count === 0 -> takror update, hech narsa o'zgarmadi (duplicate xavfsiz).
  if (res.count > 0) await ctx.reply('Tolov qabul qilindi. Rahmat!');
});

