const api = express();
api.use(express.json());

api.post('/api/me', async (req, res) => {
  // initData'ni maxsus header orqali yuboramiz.
  const initData = req.header('X-Telegram-Init-Data') ?? '';
  try {
    // Imzo va auth_date backendda tekshiriladi - frontendga ishonmaymiz.
    const verified = verifyInitData(initData, process.env.BOT_TOKEN!, 3600);
    if (!verified.user) return res.status(401).json({ error: 'user yoq' });

    // Endi verified.user.id ishonchli - shu bo'yicha DB'dan profil olamiz.
    const profile = await db.user.findUnique({
      where: { telegramId: BigInt(verified.user.id) },
    });
    res.json({ id: verified.user.id, name: verified.user.first_name, profile });
  } catch (err) {
    // Buzilgan hash yoki eskirgan initData -> 401 (spoofing urinishi).
    res.status(401).json({ error: (err as Error).message });
  }
});

api.listen(process.env.API_PORT || 4000);

import { createHmac, timingSafeEqual } from 'node:crypto';

interface VerifiedInitData {
  user?: { id: number; first_name: string; username?: string };
  authDate: Date;
  raw: URLSearchParams;
}

/**
 * Telegram Mini App initData'ni tekshiradi.
 * Algoritm: https://core.telegram.org/bots/webapps#validating-data-received-via-the-mini-app
 * @param initData - window.Telegram.WebApp.initData (querystring)
 * @param botToken - BotFather bergan token (faqat backendda!)
 * @param maxAgeSeconds - initData necha soniya amal qiladi
 */
export function verifyInitData(
  initData: string,
  botToken: string,
  maxAgeSeconds = 3600,
): VerifiedInitData {
  const params = new URLSearchParams(initData);

  // 1. Kelgan hash'ni ajratib olamiz - u data_check_string'ga kirmaydi.
  const receivedHash = params.get('hash');
  if (!receivedHash) throw new Error('initData: hash yoq');
  params.delete('hash');

  // 2. data_check_string: key=value juftliklar alfavit tartibida, \n bilan.
  const dataCheckString = [...params.entries()]
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([key, value]) => `${key}=${value}`)
    .join('\n');

  // 3. Secret key: HMAC_SHA256(bot_token, key='WebAppData').
  //    Diqqat: kalit - "WebAppData" matni, data - bot token.
  const secretKey = createHmac('sha256', 'WebAppData')
    .update(botToken)
    .digest();

  // 4. Kutilgan hash: HMAC_SHA256(data_check_string, secret_key) hex korinishida.
  const expectedHash = createHmac('sha256', secretKey)
    .update(dataCheckString)
    .digest('hex');

  // 5. Timing-safe solishtirish - oddiy === timing attack'ka ochiq.
  const a = Buffer.from(expectedHash, 'hex');
  const b = Buffer.from(receivedHash, 'hex');
  if (a.length !== b.length || !timingSafeEqual(a, b)) {
    throw new Error('initData: hash mos emas (spoofing?)');
  }

  // 6. auth_date eskirmaganini tekshiramiz - replay attack'ka qarshi.
  const authDate = Number(params.get('auth_date') ?? 0);
  if (Date.now() / 1000 - authDate > maxAgeSeconds) {
    throw new Error('initData: muddati otgan');
  }

  const userJson = params.get('user');
  return {
    user: userJson ? JSON.parse(userJson) : undefined,
    authDate: new Date(authDate * 1000),
    raw: params,
  };
}

import type { MyContext } from './context';
import { bot } from './bot';

// 1. Minimal structured logger - har yozuv qidiriladigan JSON qatori.
type Level = 'info' | 'warn' | 'error';
function log(level: Level, event: string, fields: Record<string, unknown> = {}) {
  // JSON.stringify -> Grafana/Datadog kabi tizimlar oson parse qiladi.
  console.log(JSON.stringify({ ts: new Date().toISOString(), level, event, ...fields }));
}
export const logger = {
  info: (e: string, f?: Record<string, unknown>) => log('info', e, f),
  warn: (e: string, f?: Record<string, unknown>) => log('warn', e, f),
  error: (e: string, f?: Record<string, unknown>) => log('error', e, f),
};

// 2. Har update uchun timing va kontekstni bir joyda log qilamiz.
bot.use(async (ctx: MyContext, next) => {
  const started = Date.now();
  await next();
  logger.info('update_handled', {
    updateId: ctx.update.update_id,
    userId: ctx.from?.id,
    durationMs: Date.now() - started,
  });
});

// 3. Global error handler: to'liq xatoni faqat logga, foydalanuvchiga xavfsiz matn.
bot.catch((err) => {
  logger.error('bot_error', {
    updateId: err.ctx.update.update_id,
    userId: err.ctx.from?.id,
    message: (err.error as Error)?.message, // stack/secret userga chiqmaydi
  });
  err.ctx.reply('Kutilmagan xato. Keyinroq urinib koring.').catch(() => {});
});

