model User {
  id         String   @id @default(cuid())
  telegramId BigInt  @unique
  role       Role    @default(USER)
  orders     Order[]
  createdAt  DateTime @default(now())
}

model Order {
  id        String      @id @default(cuid())
  userId    String
  status    OrderStatus @default(PENDING)
  amount    Int
  payload   String      @unique
  user      User        @relation(fields: [userId], references: [id])
  createdAt DateTime    @default(now())
}

enum Role { USER ADMIN }
enum OrderStatus { PENDING PAID DELIVERED CANCELED REFUNDED }

import { pgEnum, pgTable, text, timestamp, bigint } from "drizzle-orm/pg-core";

export const role = pgEnum("role", ["USER", "ADMIN"]);

export const users = pgTable("users", {
  id: text("id").primaryKey(),
  telegramId: bigint("telegram_id", { mode: "bigint" }).unique().notNull(),
  role: role("role").default("USER").notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

import { Queue, Worker } from "bullmq";
import IORedis from "ioredis";
import { env } from "../config";

export const redis = new IORedis(env.REDIS_URL, { maxRetriesPerRequest: null });

export const notificationQueue = new Queue("notifications", { connection: redis });

export async function enqueueNotification(userId: string, text: string) {
  return notificationQueue.add("send", { userId, text }, {
    attempts: 5,
    backoff: { type: "exponential", delay: 1000 },
    removeOnComplete: 1000,
  });
}

